'use client'

import type { TagGroupProps, TagListProps, TagProps } from 'react-aria-components'
import { IconX } from '@tabler/icons-react'
import {
  Button,
  composeRenderProps,
  Tag as RACTag,
  TagGroup as RACTagGroup,
  TagList as RACTagList
} from 'react-aria-components'
import { twMerge } from 'tailwind-merge'
import { cn } from '@/lib/utils'

function TagGroup({ className, ...props }: TagGroupProps) {
  return (
    <RACTagGroup
      className={twMerge('flex flex-col gap-y-1 *:data-[slot=label]:font-medium', className)}
      data-slot='control'
      {...props}
    />
  )
}

export function TagList<T extends object>({ className, ...props }: TagListProps<T>) {
  return (
    <RACTagList
      className={composeRenderProps(className, (className) => cn('flex flex-wrap gap-1', className))}
      {...props}
    />
  )
}

function Tag({ children, className, ...props }: TagProps) {
  const textValue = typeof children === 'string' ? children : undefined

  return (
    <RACTag
      className={composeRenderProps(className, (className) =>
        cn(
          'inset-ring inset-ring-input outline-hidden dark:bg-input/30',
          'inline-flex items-center gap-x-1.5 py-0.5 font-medium text-xs/5',
          '[&_svg:not([class*="size-"])]:size-3 [&_svg]:pointer-events-none [&_svg]:shrink-0',
          'cursor-default rounded-full px-2',
          'focus:ring-[3px] focus:ring-ring/50 focus-visible:ring-[3px] focus-visible:ring-ring/50',
          'data-selected:inset-ring-ring/70 data-selected:bg-primary data-selected:text-primary-foreground',
          'disabled:opacity-50',
          'href' in props ? 'cursor-pointer' : 'cursor-default',
          'aria-invalid:border-destructive aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40',
          className
        )
      )}
      textValue={textValue}
      {...props}
    >
      {({ allowsRemoving }) => (
        <>
          {children}
          {allowsRemoving && (
            <Button slot='remove'>
              <IconX />
            </Button>
          )}
        </>
      )}
    </RACTag>
  )
}

Tag.Group = TagGroup

export { TagGroup, Tag }
